SELECT S.GENERO AS GENERO, COUNT(*) AS TOTAL FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(P.TIPO_PROJETO) = LOWER('pesquisa') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%qu_m%' AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'inh' AND ((P.DATA_INICIO IS NOT NULL AND P.DATA_INICIO >= (DATE('now', '-5 years'))) OR (P.DATA_TERMINO IS NOT NULL AND P.DATA_TERMINO >= (DATE('now', '-5 years')))) GROUP BY S.GENERO ORDER BY TOTAL DESC LIMIT 1